class Solution:
    def countVowels(self, word):
        vowels = set('aeiou')
        n = len(word)
        P = [0] * (n + 1)
        for i in range(n):
            P[i + 1] = P[i] + (1 if word[i] in vowels else 0)
        S = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            S[i] = S[i + 1] + P[i + 1]
        total = 0
        for i in range(n):
            total += S[i] - (n - i) * P[i]
        return total

